import{_ as e,o as a,c as n,a2 as t}from"./chunks/framework.B72_uj9U.js";const d=JSON.parse('{"title":"Why Streaming","description":"Understand the user experience and technical motivations for streaming AI responses instead of waiting for complete responses.","frontmatter":{"title":"Why Streaming","description":"Understand the user experience and technical motivations for streaming AI responses instead of waiting for complete responses."},"headers":[],"relativePath":"learn/project/07-streaming-responses/01-why-streaming.md","filePath":"learn/project/07-streaming-responses/01-why-streaming.md"}'),o={name:"learn/project/07-streaming-responses/01-why-streaming.md"};function l(r,s,p,i,c,y){return a(),n("div",null,[...s[0]||(s[0]=[t(`<h1 id="why-streaming" tabindex="-1">Why Streaming <a class="header-anchor" href="#why-streaming" aria-label="Permalink to &quot;Why Streaming&quot;">​</a></h1><blockquote><p><strong>What you&#39;ll learn:</strong></p><ul><li>Why batch responses create unacceptable latency in interactive coding agents</li><li>How streaming reduces perceived latency and enables early user feedback</li><li>What architectural changes are needed to support streaming in an agentic system</li></ul></blockquote><p>Up to this point, your agent sends a request to the Anthropic API and waits -- sometimes for ten, twenty, or even thirty seconds -- until the entire response is assembled on the server and delivered in one shot. During that wait, your user stares at a blinking cursor with zero feedback. They do not know if the agent is thinking hard, stuck in a loop, or if the network dropped. This chapter fixes that. You are going to make your agent stream responses token-by-token, just like ChatGPT, Claude, and every other modern AI interface.</p><h2 id="the-batch-response-problem" tabindex="-1">The batch response problem <a class="header-anchor" href="#the-batch-response-problem" aria-label="Permalink to &quot;The batch response problem&quot;">​</a></h2><p>Let&#39;s look at what happens with the non-streaming approach you built in Chapter 2. Your agent calls the Anthropic Messages API, and the server generates the entire response before sending anything back:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>User sends prompt ──&gt; Server generates 500 tokens ──&gt; Full response arrives</span></span>
<span class="line"><span>                      [~10-15 seconds of silence]</span></span></code></pre></div><p>For a 500-token response at roughly 30-50 tokens per second, the user waits the full generation time before seeing a single character. In a coding agent context, this is especially painful because:</p><ol><li><strong>Responses are often long.</strong> Code explanations, multi-file edits, and command sequences can run to thousands of tokens. A 2000-token response might take 40+ seconds.</li><li><strong>Users need early signal.</strong> If the agent is heading in the wrong direction, the user wants to interrupt immediately -- not after waiting half a minute for a response they will discard.</li><li><strong>Tool calls compound the wait.</strong> In an agentic loop, the model might generate a response that includes a tool call. Without streaming, you wait for the full response, execute the tool, send the result back, and wait again for another full response. Each round trip adds dead time.</li></ol><h2 id="what-streaming-gives-you" tabindex="-1">What streaming gives you <a class="header-anchor" href="#what-streaming-gives-you" aria-label="Permalink to &quot;What streaming gives you&quot;">​</a></h2><p>With streaming, the server starts sending tokens as soon as it generates them. The first token typically arrives within 200-500 milliseconds:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>User sends prompt ──&gt; First token (200ms) ──&gt; tokens flow continuously ──&gt; Done</span></span>
<span class="line"><span>                      [User sees output immediately]</span></span></code></pre></div><p>This changes the user experience in three fundamental ways:</p><p><strong>Perceived latency drops by an order of magnitude.</strong> Instead of waiting 15 seconds for a batch response, the user sees the first word in under a second. The psychological difference is enormous -- the agent feels alive and responsive.</p><p><strong>Users can interrupt early.</strong> If you see the agent writing code that uses the wrong library or taking an approach you disagree with, you can press Ctrl+C two seconds into the response instead of waiting for the whole thing. This saves both time and API costs.</p><p><strong>Tool calls start sooner.</strong> When you stream, you can detect a tool call as soon as the model starts emitting its JSON arguments. While you still need the complete JSON to execute the tool, you know a tool call is coming and can prepare for it. More importantly, the text content before a tool call displays immediately.</p><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>In Python, the difference between batch and streaming is often just adding <code>stream=True</code> to your API call:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Batch (blocking, waits for full response)</span></span>
<span class="line"><span style="color:#CDD6F4;">response </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> client</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">messages</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">create</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">model</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;claude-sonnet-4-20250514&quot;</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> messages</span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;">messages</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> max_tokens</span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;">1024</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Streaming (yields chunks as they arrive)</span></span>
<span class="line"><span style="color:#CBA6F7;">with</span><span style="color:#CDD6F4;"> client</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">messages</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">stream</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">model</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;claude-sonnet-4-20250514&quot;</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> messages</span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;">messages</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> max_tokens</span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;">1024</span><span style="color:#9399B2;">)</span><span style="color:#CBA6F7;"> as</span><span style="color:#CDD6F4;"> stream</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CBA6F7;">    for</span><span style="color:#CDD6F4;"> text </span><span style="color:#CBA6F7;">in</span><span style="color:#CDD6F4;"> stream</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">text_stream</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#FAB387;font-style:italic;">        print</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">text</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> end</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;&quot;</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> flush</span><span style="color:#94E2D5;">=</span><span style="color:#CBA6F7;">True</span><span style="color:#9399B2;">)</span></span></code></pre></div><p>The Python SDK hides the SSE parsing, HTTP chunking, and buffering behind a clean iterator. In Rust, you will build each of those layers yourself, which gives you much finer control over performance and error handling.</p></div><h2 id="architectural-implications" tabindex="-1">Architectural implications <a class="header-anchor" href="#architectural-implications" aria-label="Permalink to &quot;Architectural implications&quot;">​</a></h2><p>Streaming is not just a UI improvement -- it requires rethinking several parts of your agent&#39;s architecture. Here is what changes:</p><h3 id="the-http-layer" tabindex="-1">The HTTP layer <a class="header-anchor" href="#the-http-layer" aria-label="Permalink to &quot;The HTTP layer&quot;">​</a></h3><p>Your current <code>reqwest</code> call uses <code>.json()</code> on the response, which buffers the entire body into memory before deserializing. For streaming, you switch to reading the response body as a <code>Stream</code> of bytes. You will need to handle:</p><ul><li><strong>Chunked transfer encoding</strong> -- the HTTP mechanism that lets the server send data in pieces.</li><li><strong>SSE parsing</strong> -- the Server-Sent Events format that the Anthropic API uses to structure streamed data.</li><li><strong>Partial data</strong> -- chunks can arrive at arbitrary byte boundaries, splitting events mid-line.</li></ul><h3 id="the-agentic-loop" tabindex="-1">The agentic loop <a class="header-anchor" href="#the-agentic-loop" aria-label="Permalink to &quot;The agentic loop&quot;">​</a></h3><p>Your loop from Chapter 3 currently looks like this in pseudocode:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">loop</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> response </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;font-style:italic;"> call_api</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#CDD6F4;">messages</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#CBA6F7;">await</span><span style="color:#94E2D5;">?</span><span style="color:#9399B2;">;</span><span style="color:#6C7086;font-style:italic;">  // blocks until complete</span></span>
<span class="line"><span style="color:#CBA6F7;">    match</span><span style="color:#CDD6F4;"> response</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">stop_reason </span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">        StopReason</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">ToolUse</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">            execute_tools</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#CDD6F4;">response</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#CDD6F4;">            messages</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">push</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">tool_results</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">        StopReason</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">EndTurn</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#CBA6F7;"> break</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>With streaming, the loop needs to process events as they arrive rather than waiting for a complete response. The stop reason is not known until the stream ends, so you accumulate content blocks incrementally:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">loop</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CBA6F7;"> mut</span><span style="color:#CDD6F4;"> stream </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;font-style:italic;"> start_stream</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#CDD6F4;">messages</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#CBA6F7;">await</span><span style="color:#94E2D5;">?</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CBA6F7;"> mut</span><span style="color:#CDD6F4;"> accumulated </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> StreamAccumulator</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">new</span><span style="color:#9399B2;">();</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">    while</span><span style="color:#CBA6F7;"> let</span><span style="color:#F9E2AF;font-style:italic;"> Some</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">event</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> =</span><span style="color:#CDD6F4;"> stream</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">next</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">.</span><span style="color:#CBA6F7;">await</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">        match</span><span style="color:#CDD6F4;"> event</span><span style="color:#94E2D5;">?</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">            StreamEvent</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">ContentDelta</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">delta</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">                print_token</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#CDD6F4;">delta</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;">text</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#CDD6F4;">                accumulated</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">add_delta</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">delta</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#9399B2;">            }</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">            StreamEvent</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">MessageStop</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#CBA6F7;"> break</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> response </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> accumulated</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">into_message</span><span style="color:#9399B2;">();</span></span>
<span class="line"><span style="color:#CBA6F7;">    match</span><span style="color:#CDD6F4;"> response</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">stop_reason </span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">        StopReason</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">ToolUse</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#9399B2;"> {</span><span style="color:#6C7086;font-style:italic;"> /* same as before */</span><span style="color:#9399B2;"> }</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">        StopReason</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">EndTurn</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#CBA6F7;"> break</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><h3 id="content-accumulation" tabindex="-1">Content accumulation <a class="header-anchor" href="#content-accumulation" aria-label="Permalink to &quot;Content accumulation&quot;">​</a></h3><p>With batch responses, you get a complete <code>Message</code> struct with fully-formed content blocks. With streaming, you receive a sequence of deltas -- small text fragments and partial JSON chunks -- that you must assemble back into the same <code>Message</code> structure. This accumulation logic is the heart of what you will build in this chapter.</p><h3 id="error-handling" tabindex="-1">Error handling <a class="header-anchor" href="#error-handling" aria-label="Permalink to &quot;Error handling&quot;">​</a></h3><p>Batch requests either succeed or fail. Streaming introduces a third possibility: partial success. The stream might deliver 80% of a response before the connection drops. You need strategies for preserving what you received and deciding whether to retry.</p><h2 id="the-plan-for-this-chapter" tabindex="-1">The plan for this chapter <a class="header-anchor" href="#the-plan-for-this-chapter" aria-label="Permalink to &quot;The plan for this chapter&quot;">​</a></h2><p>Here is the roadmap for what you will build:</p><ol><li><strong>SSE protocol</strong> -- understand the wire format and parse raw event streams.</li><li><strong>Chunked transfer</strong> -- handle HTTP chunks that do not align with event boundaries.</li><li><strong>Token rendering</strong> -- display text deltas as they arrive.</li><li><strong>Tool call assembly</strong> -- buffer partial JSON fragments into complete tool calls.</li><li><strong>Buffering strategies</strong> -- tune the balance between responsiveness and efficiency.</li><li><strong>Interrupt handling</strong> -- let users cancel mid-stream with Ctrl+C.</li><li><strong>Backpressure</strong> -- prevent memory blowout when tokens arrive faster than the terminal can render.</li><li><strong>State machine</strong> -- model the full streaming lifecycle with Rust enums.</li><li><strong>Error recovery</strong> -- handle mid-stream failures gracefully.</li><li><strong>Reconnection</strong> -- retry dropped connections with exponential backoff.</li><li><strong>Progress display</strong> -- show spinners, token counts, and timing.</li><li><strong>Real-time UI</strong> -- integrate streaming with the terminal display layer.</li></ol><p>Each piece builds on the last. By the end of this chapter, your agent will feel as responsive as any commercial coding assistant.</p><div class="custom-block wild"><p class="custom-block-title">In the Wild</p><p>Every production coding agent uses streaming. Claude Code streams all responses and uses the streaming events to drive its terminal UI in real time -- tool call indicators appear as soon as the model starts generating a tool_use block, not when it finishes. OpenCode similarly streams all API responses, parsing SSE events to update its Bubble Tea TUI incrementally. The non-streaming path exists only as a fallback for debugging.</p></div><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>Batch responses create unacceptable latency for interactive agents -- users wait the full generation time before seeing any output.</li><li>Streaming delivers the first token in under a second, enabling early interruption and a dramatically better user experience.</li><li>Adopting streaming requires changes at every layer: HTTP transport, event parsing, content accumulation, the agentic loop, and error handling.</li><li>The rest of this chapter builds each streaming component from the ground up, starting with the SSE protocol.</li></ul>`,37)])])}const u=e(o,[["render",l]]);export{d as __pageData,u as default};
